mapper.select:
SELECT r.id AS id, r.register_no AS registerNo, r.pet_id AS petId, r.owner_user_id AS customerId, r.doctor_id AS doctorId, COALESCE(si.service_name, '普通门诊') AS serviceType, COALESCE(r.symptom, r.triage_note, '') AS reason, CASE WHEN r.status = 0 THEN 'WAITING' WHEN r.status = 1 THEN 'IN_PROGRESS' WHEN r.status = 2 THEN 'DONE' WHEN r.status = 3 THEN 'CANCELED' WHEN r.status = 'WAITING' THEN 'WAITING' WHEN r.status = 'IN_PROGRESS' THEN 'IN_PROGRESS' WHEN r.status = 'DONE' THEN 'DONE' WHEN r.status = 'CANCELED' THEN 'CANCELED' ELSE 'WAITING' END AS status, r.amount AS amount, r.register_time AS visitTime, r.accept_time AS acceptTime, r.create_time AS createTime, p.name AS petName, COALESCE(p.species, p.type, '') AS petSpecies, d.name AS doctorName, COALESCE(u.real_name, '') AS customerName, COALESCE(u.phone, '') AS phone FROM register_record r LEFT JOIN pet p ON r.pet_id = p.id LEFT JOIN sys_user u ON r.owner_user_id = u.id LEFT JOIN doctor_profile d ON r.doctor_id = d.id LEFT JOIN service_item si ON r.service_item_id = si.id WHERE 1=1
AND r.status = #{status}
AND ( p.name LIKE CONCAT('%', #{keyword}, '%') OR u.real_name LIKE CONCAT('%', #{keyword}, '%') OR u.phone LIKE CONCAT('%', #{keyword}, '%') OR d.name LIKE CONCAT('%', #{keyword}, '%') OR r.register_no LIKE CONCAT('%', #{keyword}, '%') )
AND r.doctor_id = #{doctorId}
ORDER BY r.register_time DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM register_record r LEFT JOIN pet p ON r.pet_id = p.id LEFT JOIN sys_user u ON r.owner_user_id = u.id WHERE 1=1
AND r.status = #{status}
AND ( p.name LIKE CONCAT('%', #{keyword}, '%') OR u.real_name LIKE CONCAT('%', #{keyword}, '%') OR u.phone LIKE CONCAT('%', #{keyword}, '%') OR r.register_no LIKE CONCAT('%', #{keyword}, '%') )
AND r.doctor_id = #{doctorId}
